var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"최상층인데도 생체 반응이 감지되지 않는군요.","JPN":"最上層なのに生体反応が感知されませんね。","ENG":"I am on the top floor yet I sense no signs of life.","TWN":"最上層也沒有感應到生物反應。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However…","TWN":"不過……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……침식파 반응은 아주 선명합니다.","JPN":"……侵食波反応は非常に鮮明です。","ENG":"…The Corruption Ray signatures are clearer than ever.","TWN":"……侵蝕波反應非常明顯。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 많이 지쳤구나. 동력이 얼마 남지 않았나 보네.","JPN":"フフッ、だいぶお疲れのようね。動力があまり残っていないのかしら。","ENG":"Heh. You must be pooped. I guess you don't have much juice left in you.","TWN":"呵呵～你累了嗎？動能似乎沒剩多少喔～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"다시 만나서 반가워. 호라이즌. 널 기다리고 있었어.","JPN":"また会えて嬉しいわ、ホライズン。あなたを待っていたの。","ENG":"Nice to see you again, Horizon. I've been expecting you.","TWN":"真開心又見到你，地平線。我一直在等你呢～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……셰나.","JPN":"……シェナ。","ENG":"…Shena.","TWN":"……世娜。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들에게는 관심없습니다. 처음부터 윌버만 곱게 내놓으면 끝날 일이었습니다.","JPN":"あなたたちには興味ありません。最初からウィルバーさえ大人しく譲ってくれれば終わる話です。","ENG":"I have no business with you. This could have ended swiftly if you would have simply surrendered Wilbur to me.","TWN":"我的重點不是你們，一開始只要乖乖把韋爾伯交出來就沒事了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄, 그런 것치고는 우리 연구 시설을 죄다 부수고 다니던걸?","JPN":"まあ、そんなことを言いながら、うちの研究施設を手当たり次第壊しまくっているじゃない。","ENG":"I don't know about that. I mean, you've been smashing all of our research centers!","TWN":"是這樣嗎？這有到需要把我們的研究設施全都毀掉的程度？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"거짓말이 서툰 거 아냐, 호라이즌?","JPN":"嘘が下手なんじゃない？　ホライズン。","ENG":"You're not a very good liar, are you Horizon?","TWN":"你很不擅長說謊呢，地平線。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 솔직하지 못한 점도 귀엽네.","JPN":"フフッ。素直じゃないところも可愛いわ。","ENG":"Heh. I even find your dishonesty just adorable.","TWN":"呵呵～不敢說實話的樣子也很可愛呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 탓이야, 호라이즌. 계속 그렇게 유혹하니까 가지고 놀고 싶어지잖아.","JPN":"あなたのせいよ、ホライズン。そうやってずっと誘惑してくるから遊んでみたくなるじゃない。","ENG":"This is all your fault, Horizon. You tempting me like that makes me want to play with you.","TWN":"都是你不好～誰叫你一直誘惑我，害我越想逗著你玩。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇지 않았으면, 저 얼빠진 인간 따위 진즉 내 손으로 죽여 버렸을 텐데.","JPN":"そうでなければ、あんなクズ人間なんかさっさと私の手で殺してやったのに。","ENG":"Otherwise, I would have killed that fool myself a long time ago.","TWN":"否則我早就親手處理掉那個愚蠢的人類了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신도 학회 소속 아니었습니까. 학회에서 그를 더 이상 비호하지 않기로 했나 보군요.","JPN":"あなたも学会所属だったと思いますが。学会では彼をこれ以上庇護しないことにしたのですね。","ENG":"But aren't you an associate of the Society? I take it that the Society has decided to no longer protect the man.","TWN":"你不也是學會的人嗎？看來是學會下令不再保護他的安危嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 감찰관까지 행차하셨으니 당연한 이야기지. 옥상으로 간 바보는 아직 상황 파악이 안 됐지만.","JPN":"まあ、監察官様までお出ましになったんだから当然の話よ。屋上に行ったあのバカはまだ状況が把握できていないようだけど。","ENG":"Well, duh. They even sent an inspector. That fool running off to the rooftop still has no idea though.","TWN":"都已經派監察委員來到這裡，這不是很明顯嗎？只是屋頂上的那個傻瓜還搞不清楚狀況～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 오해하지 마. 일단 신세는 지고 있어도 <color=#ffd34c>우리</color>한테는 학회의 철칙보다 더 중요한 게 있거든.","JPN":"でも誤解しないで。一応お世話になってはいるけど<color=#ffd34c>私たち</color>には学会の鉄則よりもっと重要なものがあるから。","ENG":"Don't let it fool you though. We may be hanging our hats with the Society for now, but there's something more important that the Society's rules for <color=#ffd34c>us</color>.","TWN":"不過你別誤會，雖然暫時依附在學會底下，但對<color=#ffd34c>我們</color>而言，有比學會的指令更重要的東西。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멘탈 프린팅 기술입니까?","JPN":"メンタル・プリンティング技術ですか？","ENG":"You mean the Mental Printing technology?","TWN":"智力複印技術嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정확해.","JPN":"そのとおり。","ENG":"Exactly.","TWN":"沒錯。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"건물을 오르던 도중에 당신들이 A타입이라고 부르는 실험체들과 마주쳤습니다.","JPN":"建物を上っている途中、あなたたちがAタイプと呼んでいる実験体に遭遇しました。","ENG":"I encountered what you lot call \\"Type A's\\" on my way up the building.","TWN":"我在來這裡的路上，有遇到你們所謂的A型實驗體。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 그림자가 왜 그런 것에 집착하는지는 이해할 수 없군요.","JPN":"しかし、シャドウがなぜあんなものに執着するのか理解できませんね。","ENG":"It does not compute why a Shadow would obsess over such things.","TWN":"只是我無法理解，暗影為何如此執著於此。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관성이야, 호라이즌. 너희가 <color=#ffd34c>그림자</color>라고 부르는 우리들은 모두 관성에 사로잡혀 있어.","JPN":"習性よ、ホライズン。あなたたちが<color=#ffd34c>シャドウ</color>と呼んでいる私たちはみんな習性にとらわれているの。","ENG":"It's a force of habit. Something that all of us <color=#ffd34c>Shadows</color> as you call us are prone to.","TWN":"這是慣性，地平線。你們口中稱為<color=#ffd34c>暗影</color>的我們，都受制於慣性。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"알을 깨고 나온 병아리가 처음 보는 것을 부모라고 여기듯이.","JPN":"割れた卵から出てきたヒヨコが、初めて見るものを親だと思うのと同じ。","ENG":"It's just like how the chick hatching out of the egg considers the first creature it sees as its mother.","TWN":"就像小雞破殼而出後，會將第一眼看到的東西認為是父母親。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리 역시, 그림자를 남긴 자가 생애 마지막으로 남긴 집착에 사로잡히는 거야.","JPN":"私たちも、シャドウを残した者が生涯最後に執着したものに囚われるのよ。","ENG":"Likewise, we Shadows are prisoners to the final obsession held by our original copies in their lives.","TWN":"我們也是一樣，會受制於留下暗影的人，在最後一刻遺留下的執著。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……연구 시설들을 거쳐 오면서 획득한 파편화된 데이터들을 취합했습니다.","JPN":"……これまで通ってきた研究施設で破片化されたデータを収集しました。","ENG":"…I've put together the fragmented data I've collected in each research facility.","TWN":"……我已經將在這些研究設施中，拿到的碎片化資料整合起來。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"첫 번째는 인간 복제. 변수를 차단하기 위해 자의식이 없는 인간을 만드는 과정이었죠.","JPN":"一つ目は人間の複製。不確定要素を排除するために、自意識のない人間を作る過程でした。","ENG":"The first is human cloning. A process to create humans without consciousness in order to prevent any uncertain variables.","TWN":"第一個是複製人。也就是為防止變數，而創造出沒有自我意識的人類。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"두 번째는 능력 연구. 어떤 조건 하에 카운터의 능력이 형성되는지 분석합니다.","JPN":"二つ目は能力研究。どのような条件でカウンターの能力が形成されるかを分析します。","ENG":"The second is capability research. It analyzes the conditions under which Counter powers manifest.","TWN":"第二個是研究能力。也就是分析在什麼條件下，會形成制裁者的能力。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"세 번째는 인격 이식. 각성한 카운터의 기억과 성격을 타인의 뇌에 덮어씌워 동일한 각성을 촉발시킨다…….","JPN":"三つ目は人格移植。覚醒したカウンターの記憶と性格を他人の脳にのせて同一の覚醒を触発させる……","ENG":"The third is personality transplantation. By overriding a subject's brain with the memories and personality of a powered Counter, the process catalyzes the manifestation of the same powers…","TWN":"第三個是人格移植。也就是將覺醒制裁者的記憶和個性，覆蓋到另一人的腦袋裡，以觸發相同的覺醒……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기술의 최종적인 목표는, 인위적으로 일반인을 카운터로 각성시키는 것입니까?","JPN":"技術の最終的な目標は、人為的に一般人をカウンターに覚醒させることですか？","ENG":"Is the final goal of this technology to artificially turn ordinary people into Counters?","TWN":"這個技術的最終目的，是希望用人為的方式，將普通人覺醒成制裁者嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"호오. 요점만 잘 정리했네? 우리 연구원 안 할래?","JPN":"あら、要点だけをよくまとめてくれたわね。うちの研究員になるのはどう？","ENG":"Ooh... You really covered all the key points so succinctly! How would you like to work for us as a researcher?","TWN":"哇喔～很會整理重點喔！要不要來當我們的研究員？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"부정. 그런 엉터리 연구에 협조해서 제 커리어를 망칠 계획 없습니다.","JPN":"否定。そんなでたらめな研究に協力して自分のキャリアに汚点を残すつもりはありません。","ENG":"Denied. I have no interest in ruining my career by participating in such hogwash research.","TWN":"拒絕，我不想因為幫助那種無良研究而毀掉事業。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 형이상학적인 관점에서 접근하면 성공 가능성을 다시 생각해야 할 걸.","JPN":"フフッ。形而上学的な観点からアプローチすれば、成功の可能性について考え直すことになるわよ。","ENG":"Heh. If you approach it from a metaphysical angle, you'll have to rethink the chance of success.","TWN":"呵呵～就形上學的觀點而言，應該是先做才考慮成功的可能性。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금은 걸음마 수준이야. 이번 세계에서는 한 번 실패하는 바람에 처음부터 다시 시작해야 했으니까.","JPN":"今は初歩的な段階なの。今回の世界では一度失敗したせいで、最初からやり直さなければならなかったもの。","ENG":"These are just baby steps compared to what we'll achieve later. We had to start again from scratch because we already failed in this world once, after all.","TWN":"現在才剛起步而已，這次的世界曾經失敗過一次，所以必須重頭開始。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설령 그런 식으로 전 인류를 카운터로 만들 수 있다고 해도, 무슨 의미가 있습니까?","JPN":"たとえそのやり方で全人類をカウンターにできたとしても、何の意味があるのですか？","ENG":"Even if you could turn all of humanity into Counters, where's the meaning in that?","TWN":"假設，真的可以用那樣的技術，將全人類打造成制裁者，那又有什麼意義？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄, 인간들도 전부 의미 있는 선택을 하지는 않잖아?","JPN":"さあね、人間だってみんな意味のある選択をするわけではないでしょ？","ENG":"Well, humans don't always make meaningful choices either, do they?","TWN":"這個嘛～人類的選擇也不全都是有意義的吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금 너처럼 말이야.","JPN":"今のあなたのようにね。","ENG":"Like you right now, for instance.","TWN":"就跟現在的你一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……비키라는 말은 하지 않겠습니다. 셰나.","JPN":"……退いてくださいとは言いません、シェナ。","ENG":"…I won't ask you to step aside, Shena.","TWN":"…… 世娜，我不會叫你閃開。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정답이야, 호라이즌. 너와 합주할 이 순간을…….","JPN":"正解よ、ホライズン。あなたと合奏するこの瞬間を……","ENG":"I was hoping you'd say that, Horizon. I've been looking forward to this duet…","TWN":"這才對嘛，地平線。和你一起合奏的這個瞬間……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정말 애타게 기다리고 있었으니까.","JPN":"ずっと待ち焦がれていたんだから。","ENG":"…with immense anticipation, after all.","TWN":"我可是一直很熱切期待呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};